#!/bin/zsh\n\n# Source environment variables for Stripe API key\nif [[ -f ~/.openclaw/workspace/.env.stripe_secret ]]; then\n  source ~/.openclaw/workspace/.env.stripe_secret\nelse\n  echo \"Error: ~/.openclaw/workspace/.env.stripe_secret not found.\" >> ~/.openclaw/workspace/email_delivery_error.log\n  exit 1\nfi\n\nif [[ -z \"$STRIPE_SECRET_KEY\" ]]; then\n  echo \"Error: STRIPE_SECRET_KEY not set in environment.\" >> ~/.openclaw/workspace/email_delivery_error.log\n  exit 1\nfi\n\nWORKSPACE_DIR=\"/Users/beeassistant/.openclaw/workspace\"\nSENT_REPORTS_LOG=\"${WORKSPACE_DIR}/sent_reports.log\"\nERROR_LOG=\"${WORKSPACE_DIR}/email_delivery_error.log\"\n\n# Ensure log files exist\ntouch \"$SENT_REPORTS_LOG\"\ntouch \"$ERROR_LOG\"\n\n# Calculate timestamp for sessions in the last 15 minutes\n# (Stripe list API uses 'created' timestamp for filtering)\n# Convert current time to Unix timestamp, subtract 15 minutes (900 seconds)\n# Since Stripe API does not allow 'created[gt]' with relative time, \n# we fetch recent sessions and filter them in the script.\n\n# Fetch recent successful checkout sessions from Stripe\n# Note: This fetches up to 100 recent sessions. For very high volume, pagination would be needed.\nSTRIPE_RESPONSE=$(curl -s -X GET \"https://api.stripe.com/v1/checkout/sessions?limit=100&expand[]=data.line_items\" \\\n  -u \"$STRIPE_SECRET_KEY:\" \\\n  -H \"Content-Type: application/x-www-form-urlencoded\")\n\n# Check for cURL errors\nif [[ $? -ne 0 ]]; then\n  echo \"$(date -u): cURL error fetching Stripe sessions.\" >> \"$ERROR_LOG\"\n  echo \"Response: $STRIPE_RESPONSE\" >> \"$ERROR_LOG\"\n  exit 1\nfi\n\n# Check for Stripe API errors (e.g., authentication)\nif echo \"$STRIPE_RESPONSE\" | grep -q \"\\\"error\\\":\"; then\n  echo \"$(date -u): Stripe API error fetching sessions.\" >> \"$ERROR_LOG\"\n  echo \"Response: $STRIPE_RESPONSE\" >> \"$ERROR_LOG\"\n  exit 1\nfi\n\n# Process each session\necho \"$STRIPE_RESPONSE\" | jq -c \'.data[] | select(.status == \"complete\" and .payment_status == \"paid\")\' | while read -r session_json;\ndo\n  SESSION_ID=$(echo \"$session_json\" | jq -r \'.id\')\n  CUSTOMER_EMAIL=$(echo \"$session_json\" | jq -r \'.client_reference_id\')\n  REPORT_NAME=$(echo \"$session_json\" | jq -r \'.metadata.reportName\')\n  GDPR_CONSENT=$(echo \"$session_json\" | jq -r \'.metadata.gdprConsent\')\n  CUSTOMER_IDEA=$(echo \"$session_json\" | jq -r \'.metadata.customerIdea // \"\"\') # Custom report idea, if any\n\n  # Check if email is valid and consent was given\n  if [[ \"$CUSTOMER_EMAIL\" == \"null\" || -z \"$CUSTOMER_EMAIL\" || \"$GDPR_CONSENT\" != \"true\" ]]; then\n    echo \"$(date -u): Skipping session $SESSION_ID: Invalid email ($CUSTOMER_EMAIL) or no GDPR consent.\" >> \"$ERROR_LOG\"\n    continue\n  fi\n\n  # Check if report has already been sent\n  if grep -q \"$SESSION_ID\" \"$SENT_REPORTS_LOG\"; then\n    # echo \"$(date -u): Report for session $SESSION_ID already sent. Skipping.\" # Commented to avoid log spam\n    continue\n  fi\n\n  # Determine report file path\n  REPORT_FILE=\"\"\n  if [[ \"$REPORT_NAME\" == \"Custom Side Hustle Report\" ]]; then\n    REPORT_FILE=\"${WORKSPACE_DIR}/reports/paid/custom-report-placeholder.html\"\n  elif [[ \"$REPORT_NAME\" != \"null\" && -n \"$REPORT_NAME\" ]]; then\n    NORMALIZED_NAME=$(echo \"$REPORT_NAME\" | tr \'[:upper:]\' \'[:lower:]\' | sed \'s/[^a-z0-9]+/-\/g; s/^-|-$//g\')\n    REPORT_FILE=\"${WORKSPACE_DIR}/reports/paid/${NORMALIZED_NAME}-2026.html\"\n  fi\n\n  if [[ ! -f \"$REPORT_FILE\" ]]; then\n    echo \"$(date -u): Error: Report file not found for $REPORT_NAME (path: $REPORT_FILE).\" >> \"$ERROR_LOG\"\n    continue\n  fi\n\n  # Construct email subject and body\n  EMAIL_SUBJECT=\"Your Side Hustle Lab Report: $REPORT_NAME\"\n  EMAIL_BODY=\"Hi there,\\n\\nThank you for your purchase from Side Hustle Lab!\\n\\nAttached is your '$REPORT_NAME' report. We hope it provides you with valuable insights to kickstart your side hustle journey.\\n\\nIf you have any questions, feel free to reply to this email.\\n\\nBest regards,\\nBee and the Side Hustle Lab Team\\n\\n(This email was sent automatically.)\"\n\n  # Send email using himalaya\n  # Note: himalaya needs to be configured to send from bee.assistant1@gmail.com\n  # The -o flag saves the email to a file, so it needs a unique name or careful handling\n  # For this cron, we assume himalaya is already configured for sending directly.\n  # Here, we use a template with content and attachment. \n  # IMPORTANT: Himalaya needs to be able to access the attachment file.\n  \n  # Escape single quotes within REPORT_FILE, EMAIL_SUBJECT, EMAIL_BODY for safe shell execution\n  ESCAPED_REPORT_FILE=$(printf %q \"$REPORT_FILE\")\n  ESCAPED_EMAIL_SUBJECT=$(printf %q \"$EMAIL_SUBJECT\")\n  ESCAPED_EMAIL_BODY=$(printf %q \"$EMAIL_BODY\")\n\n  # Construct the himalaya command. Need to ensure the template send supports attachments well.\n  # Using a direct raw template approach for maximum control.\n  HIMALAYA_COMMAND=$(cat <<EOF\nhimalaya template send \\\n  --to \"$CUSTOMER_EMAIL\" \\\n  --from \"bee.assistant1@gmail.com\" \\\n  --subject \"$EMAIL_SUBJECT\" \\\n  --text-content \"$EMAIL_BODY\" \\\n  --attachments \"$REPORT_FILE\"\nEOF\n)\n\n  # Execute himalaya command\n  if eval \"$HIMALAYA_COMMAND\" 2>>\"$ERROR_LOG\"; then\n    echo \"$(date -u): Successfully sent report for session $SESSION_ID to $CUSTOMER_EMAIL.\" >> \"$SENT_REPORTS_LOG\"\n  else\n    echo \"$(date -u): Error sending report for session $SESSION_ID to $CUSTOMER_EMAIL.\" >> \"$ERROR_LOG\"\n  fi\n\ndone\n\n# Clean up any temporary files or logs if needed\n\nexit 0